verification.command:
extract() { awk '
  /^## \[0\.7\.0\]/ { in_span=1; next }
  in_span && /^## \[/ { exit }
  in_span { print }
' "$1"; }
span=$(extract CHANGELOG.md)
[ -n "$span" ] || { echo 'empty [0.7.0] span'; exit 1; }
for tok in 'ecosystem' 'preflight_verdict.schema.json' 'ecosystem_baseline.schema.json' 'engineering_finding.schema.json' 'ecosystem_preflight.py' 'C12' 'NIP-0001'; do
  echo "$span" | grep -qF -- "$tok" || { echo "missing token in [0.7.0] section: $tok"; exit 1; }
done
echo PASS

extract() { awk '
  /^## \[0\.7\.0\]/ { in_span=1; next }
  in_span && /^## \[/ { exit }
  in_span { print }
' "$1"; }
span=$(extract CHANGELOG.md)
echo "$span" | grep -qF '0.7.0' || { echo 'no 0.7.0 metadata-bump mention in real [0.7.0] section content'; exit 1; }
echo "$span" | grep -qF 'C1-C12' || { echo 'no C1-C12 capability-summary fix mention'; exit 1; }
echo PASS

extract() { awk '
  /^## Module Map/ { in_span=1; next }
  in_span && /^## / { exit }
  in_span { print }
' "$1"; }
span=$(extract CONTEXT.md)
echo "$span" | grep -qF '`ecosystem/`' || { echo 'missing ecosystem/ Module Map bullet within the Module Map section span'; exit 1; }
source tools/verify_lib.sh && vlib_version_increased CONTEXT.md && echo PASS || { echo 'CONTEXT.md version not strictly increased'; exit 1; }

f=.agent/evidence/045-release-readiness-checklist.md
test -f "$f" || { echo 'checklist missing'; exit 1; }
n=$(grep -c . "$f")
[ "$n" -eq 8 ] || { echo "expected exactly 8 non-blank lines, got $n"; exit 1; }
for i in 1 2 3 4 5 6 7 8; do
  c=$(grep -cE "^${i}\." "$f")
  [ "$c" -eq 1 ] || { echo "item ${i} label must appear exactly once, found ${c}"; exit 1; }
done
grep -qxF '7. Human sign-off complete: PENDING -- human-gated (H-FRAMEWORK-RELEASE)' "$f" || { echo 'item 7 is not byte-identical to the pinned literal'; exit 1; }
grep -qxF '8. Immutable tag published: PENDING -- human-gated (H-FRAMEWORK-RELEASE)' "$f" || { echo 'item 8 is not byte-identical to the pinned literal'; exit 1; }
h=$(sha256sum "$f" | awk '{print $1}')
[ "$h" = "06f266c06abd9b3793477771de265698dbec0a00761c6d81818decbc7e31b5ea" ] || { echo "checklist content does not match the pinned exact byte content (got $h)"; exit 1; }
echo PASS
